auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.90;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks; // stacks[i] = bottom to top, 0-indexed box values
    std::vector<int> box_stack; // which stack is box in
    std::vector<int> box_pos;  // position in that stack (0 = bottom)

    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record;

    State() : N(0), M(0), energy(0), record(true) {}

    State(int n, int m, const std::vector<std::vector<int>>& init, bool rec = true)
        : N(n), M(m), energy(0), record(rec) {
        stacks = init;
        box_stack.resize(N);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_pos[stacks[i][j]] = j;
            }
        }
        if (record) ops.reserve(N * 3);
    }

    // Move box v and everything above it to dest stack
    // v is 0-indexed box value
    void move(int v, int dest) {
        int src = box_stack[v];
        int pos = box_pos[v];
        int num_moved = (int)stacks[src].size() - pos;

        int dest_base = (int)stacks[dest].size();
        for (int i = pos; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_pos[b] = dest_base + (i - pos);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(pos);

        energy += num_moved + 1;
        if (record) ops.push_back({v + 1, dest + 1});
    }

    // Carry out box v (must be on top of its stack)
    void carry_out(int v) {
        int src = box_stack[v];
        stacks[src].pop_back();
        if (record) ops.push_back({v + 1, 0});
    }

    bool is_on_top(int v) {
        int src = box_stack[v];
        return box_pos[v] == (int)stacks[src].size() - 1;
    }

    int depth_from_top(int v) {
        int src = box_stack[v];
        return (int)stacks[src].size() - 1 - box_pos[v];
    }
};

// Evaluate how good a destination is for a "waste" chunk
// Lower score = better destination
double eval_dest_for_waste(const State& state, int dest, int current_target, int chunk_size) {
    double score = 0.0;
    const auto& dstack = state.stacks[dest];

    // Penalize covering soon-needed boxes
    for (int i = (int)dstack.size() - 1; i >= 0; i--) {
        int b = dstack[i];
        if (b > current_target && b < current_target + 30) {
            // This box is needed soon and we'd be covering it
            score += 50.0 / (b - current_target);
        }
    }

    // Slight preference for taller stacks (concentrate waste)
    score -= (double)dstack.size() * 0.01;

    // Penalize empty stacks slightly (they're valuable buffer space)
    if (dstack.empty()) score += 2.0;

    return score;
}

// Evaluate destination for a chunk whose top box is a "critical" upcoming box
// The critical box will be carried out immediately, so what matters is where the REST of the chunk ends up
double eval_dest_for_critical(const State& state, int dest, int current_target,
                              const std::vector<int>& chunk, int critical_box) {
    double score = 0.0;
    const auto& dstack = state.stacks[dest];

    // After critical_box is carried out, the rest of the chunk stays
    // Penalize covering soon-needed boxes on the destination
    for (int b : dstack) {
        if (b > current_target && b < current_target + 30) {
            score += 50.0 / (b - current_target);
        }
    }

    // Penalize if the remaining chunk (below critical) contains soon-needed boxes
    // that would be buried by stuff on the dest stack... actually they go ON TOP of dest
    // so the remaining chunk is on top. Good.

    // Prefer shorter stacks for critical chunks (to keep things accessible)
    score += (double)dstack.size() * 0.05;

    return score;
}

int best_waste_dest(const State& state, int current_target, int src_stack, int chunk_size) {
    double best_score = 1e18;
    int best_dest = -1;
    for (int d = 0; d < state.M; d++) {
        if (d == src_stack) continue;
        double s = eval_dest_for_waste(state, d, current_target, chunk_size);
        if (s < best_score) {
            best_score = s;
            best_dest = d;
        }
    }
    return best_dest;
}

int best_critical_dest(const State& state, int current_target, int src_stack,
                       const std::vector<int>& chunk, int critical_box) {
    double best_score = 1e18;
    int best_dest = -1;
    for (int d = 0; d < state.M; d++) {
        if (d == src_stack) continue;
        double s = eval_dest_for_critical(state, d, current_target, chunk, critical_box);
        if (s < best_score) {
            best_score = s;
            best_dest = d;
        }
    }
    return best_dest;
}

// Run the cascade splitting strategy
// Returns total energy
long long run_cascade(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                      std::vector<std::pair<int,int>>& out_ops, int max_splits_per_block = 3,
                      int lookahead_window = 20) {
    State state(N, M, init_stacks, true);

    for (int k = 0; k < N; k++) {
        // Check if already carried out (shouldn't happen, but safety)
        if (state.is_on_top(k)) {
            state.carry_out(k);
            continue;
        }

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos; // boxes above k

        if (block_size == 0) {
            state.carry_out(k);
            continue;
        }

        // Get the block above k (from bottom to top of the sub-block)
        // block[0] is directly above k, block[block_size-1] is at the top
        std::vector<int> block(state.stacks[src].begin() + pos + 1, state.stacks[src].end());

        // Find consecutive upcoming boxes in this block
        // We want the longest prefix k+1, k+2, k+3, ... that are ALL in this block
        std::vector<int> cascade_boxes; // boxes k+j that are in this block, sorted by j
        for (int j = 1; j <= lookahead_window && k + j < N; j++) {
            int target = k + j;
            if (state.box_stack[target] == src && state.box_pos[target] > pos) {
                cascade_boxes.push_back(target);
            }
        }

        // Find longest consecutive prefix from k+1
        std::vector<int> split_targets; // boxes we'll split for (guaranteed cascade)
        if (!cascade_boxes.empty() && cascade_boxes[0] == k + 1) {
            split_targets.push_back(k + 1);
            for (int i = 1; i < (int)cascade_boxes.size() && i < max_splits_per_block; i++) {
                if (cascade_boxes[i] == k + 1 + i) {
                    split_targets.push_back(cascade_boxes[i]);
                } else {
                    break;
                }
            }
        } else if (!cascade_boxes.empty()) {
            // k+1 is not in block but other upcoming boxes are
            // Still worth splitting for the first one if savings > 1
            int first_upcoming = cascade_boxes[0];
            int pos_in_block = state.box_pos[first_upcoming] - pos - 1; // 0-indexed in block
            int boxes_above_in_block = block_size - 1 - pos_in_block;
            if (boxes_above_in_block >= 2) {
                // Worth splitting: saves boxes_above_in_block, costs 1
                split_targets.push_back(first_upcoming);
            }
        }

        if (split_targets.empty()) {
            // No splitting, just move the whole block to best destination
            int first_box = block[0]; // bottom of block (directly above k)
            int dest = best_waste_dest(state, k, src, block_size);
            state.move(first_box, dest);
            state.carry_out(k);
        } else {
            // Split the block at each split target's position
            // split_targets are sorted by value (ascending)
            // Their positions in the block might not be sorted, need to sort by position

            // Get positions in block for each split target
            std::vector<std::pair<int,int>> target_positions; // (position_in_block, box_value)
            for (int t : split_targets) {
                int p = state.box_pos[t] - pos - 1; // 0-indexed position in block
                target_positions.push_back({p, t});
            }
            // Sort by position (ascending)
            std::sort(target_positions.begin(), target_positions.end());

            // Define chunks: split at each target position
            // Chunks from top to bottom:
            // Top waste chunk: [last_target_pos + 1, block_size - 1]
            // Then for each target (from highest pos to lowest):
            //   chunk ending at target_pos (target is on top of this chunk)

            // Build split points (positions where we cut, exclusive upper bound of lower chunk)
            std::vector<int> split_positions; // positions of targets in block
            for (auto& [p, v] : target_positions) {
                split_positions.push_back(p);
            }

            // Chunks (from top of block to bottom):
            // 1. Top waste: from split_positions.back() + 1 to block_size - 1
            // 2. For i from target_positions.size()-1 down to 1:
            //    chunk from split_positions[i-1] + 1 to split_positions[i]
            //    (target at position split_positions[i] is on top)
            // 3. Bottom chunk: from 0 to split_positions[0]
            //    (target at position split_positions[0] is on top)

            struct Chunk {
                int start; // start position in block (inclusive)
                int end;   // end position in block (inclusive)
                int critical_box; // -1 if waste chunk, else the box on top that we want
            };

            std::vector<Chunk> chunks;

            // Top waste chunk
            int top_start = split_positions.back() + 1;
            if (top_start < block_size) {
                chunks.push_back({top_start, block_size - 1, -1});
            }

            // Middle/bottom critical chunks (from top to bottom)
            for (int i = (int)target_positions.size() - 1; i >= 0; i--) {
                int chunk_end = split_positions[i];
                int chunk_start = (i > 0) ? split_positions[i-1] + 1 : 0;
                chunks.push_back({chunk_start, chunk_end, target_positions[i].second});
            }

            // Now move chunks from top to bottom
            // The chunks are ordered from top of block to bottom
            // We move the topmost chunk first

            // But wait: we need to adjust for the fact that after moving upper chunks,
            // the positions change. Actually, since we move from TOP down, each chunk
            // specifies a box at the BOTTOM of the sub-block-to-move.
            // When we move chunk[i], its bottom box is at position (pos + 1 + chunk.start)
            // in the ORIGINAL stack... but after moving upper chunks, positions shift.
            //
            // Actually, let's think about it differently. After moving the top chunk,
            // the remaining block (below it) is still there. We then move the next chunk
            // from the new top, etc.
            //
            // The key: the bottom box of each chunk remains in the same RELATIVE position
            // to box k, but absolute positions change as we remove upper chunks.
            //
            // Simpler approach: just specify the bottom box of each chunk to move.
            // The move operation picks up that box and everything above it.
            // Since we move from top to bottom, each subsequent chunk's bottom box
            // will be the new top of the remaining portion of the stack above k.
            // Wait no, that's not right either.
            //
            // Let's be concrete. After we remove the top chunk, the stack becomes:
            // [stuff below k, k, block[0], ..., block[top_start-1]]
            // Then we need to move block[chunk_start..chunk_end] which is now at the top.
            // The bottom box of that chunk is block[chunk_start].

            // Actually the issue is more subtle. Let me just reference the box values.
            for (auto& chunk : chunks) {
                int bottom_box = block[chunk.start];
                // This box and everything above it in the current stack state
                int dest;
                if (chunk.critical_box == -1) {
                    // Waste chunk
                    int sz = chunk.end - chunk.start + 1;
                    dest = best_waste_dest(state, k, src, sz);
                } else {
                    // Critical chunk - after moving, critical box is on top
                    std::vector<int> chunk_content(block.begin() + chunk.start, block.begin() + chunk.end + 1);
                    dest = best_critical_dest(state, k, src, chunk_content, chunk.critical_box);
                }
                state.move(bottom_box, dest);
            }

            // Now k should be on top of src stack
            state.carry_out(k);

            // Carry out cascade boxes that are now on top
            for (int t : split_targets) {
                if (t < N && state.is_on_top(t)) {
                    state.carry_out(t);
                    k = t; // advance k (the outer loop will increment to k+1)
                } else {
                    break; // cascade broken
                }
            }
        }
    }

    out_ops = std::move(state.ops);
    return state.energy;
}

// Also try non-consecutive splits (more aggressive)
long long run_cascade_aggressive(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                                  std::vector<std::pair<int,int>>& out_ops, int max_splits = 4,
                                  int window = 30) {
    State state(N, M, init_stacks, true);

    for (int k = 0; k < N; k++) {
        if (state.is_on_top(k)) {
            state.carry_out(k);
            continue;
        }

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos;

        if (block_size == 0) {
            state.carry_out(k);
            continue;
        }

        std::vector<int> block(state.stacks[src].begin() + pos + 1, state.stacks[src].end());

        // Find ALL upcoming boxes in the block
        std::vector<std::pair<int,int>> upcoming; // (position_in_block, box_value)
        for (int j = 1; j <= window && k + j < N; j++) {
            int target = k + j;
            if (state.box_stack[target] == src && state.box_pos[target] > pos) {
                int p_in_block = state.box_pos[target] - pos - 1;
                upcoming.push_back({p_in_block, target});
            }
        }

        // Sort by position in block
        std::sort(upcoming.begin(), upcoming.end());

        // Select which boxes to split for, based on cost-benefit
        // Cost: +1 per split
        // Benefit: for box at position p in block of size block_size,
        //          boxes above it in its chunk = (next_split_above - p - 1) if not split
        //          vs 0 if we split at p (it becomes top of chunk)

        std::vector<int> chosen_positions; // positions in block to split at

        // Always want the first consecutive run from k+1
        int consecutive_end = k;
        for (auto& [p, v] : upcoming) {
            if (v == consecutive_end + 1) {
                chosen_positions.push_back(p);
                consecutive_end = v;
                if ((int)chosen_positions.size() >= max_splits) break;
            }
        }

        // If we haven't filled max_splits, look for other high-value splits
        if ((int)chosen_positions.size() < max_splits) {
            for (auto& [p, v] : upcoming) {
                if ((int)chosen_positions.size() >= max_splits) break;
                // Skip if already chosen
                bool already = false;
                for (int cp : chosen_positions) {
                    if (cp == p) { already = true; break; }
                }
                if (already) continue;

                // Estimate benefit: boxes that would be above this box if not split
                // Find the next higher split position (or top of block)
                int next_above = block_size; // top of block
                for (int cp : chosen_positions) {
                    if (cp > p && cp < next_above) next_above = cp;
                }
                int would_be_above = next_above - p - 1;

                // Benefit estimate (discounted by distance from k)
                double benefit = (double)would_be_above / (v - k);
                if (benefit > 1.5) { // must save more than cost of 1
                    chosen_positions.push_back(p);
                    std::sort(chosen_positions.begin(), chosen_positions.end());
                }
            }
        }

        if (chosen_positions.empty()) {
            // No splitting
            int dest = best_waste_dest(state, k, src, block_size);
            state.move(block[0], dest);
            state.carry_out(k);
        } else {
            std::sort(chosen_positions.begin(), chosen_positions.end());

            // Build chunks from top to bottom
            struct Chunk {
                int start, end;
                int critical_box; // -1 if waste
            };
            std::vector<Chunk> chunks;

            // Top waste chunk
            int top_start = chosen_positions.back() + 1;
            if (top_start < block_size) {
                chunks.push_back({top_start, block_size - 1, -1});
            }

            // Critical chunks (from top to bottom)
            for (int i = (int)chosen_positions.size() - 1; i >= 0; i--) {
                int chunk_end = chosen_positions[i];
                int chunk_start = (i > 0) ? chosen_positions[i-1] + 1 : 0;
                // Find the critical box for this chunk (the one at position chunk_end)
                int crit = block[chunk_end];
                chunks.push_back({chunk_start, chunk_end, crit});
            }

            // Move chunks
            for (auto& chunk : chunks) {
                int bottom_box = block[chunk.start];
                int dest;
                if (chunk.critical_box == -1) {
                    int sz = chunk.end - chunk.start + 1;
                    dest = best_waste_dest(state, k, src, sz);
                } else {
                    std::vector<int> cc(block.begin() + chunk.start, block.begin() + chunk.end + 1);
                    dest = best_critical_dest(state, k, src, cc, chunk.critical_box);
                }
                state.move(bottom_box, dest);
            }

            state.carry_out(k);

            // Cascade: carry out consecutive boxes that are on top
            for (int cp : chosen_positions) {
                int box_val = block[cp];
                if (box_val == k + 1 || (box_val == consecutive_end && box_val == k + (int)(&cp - &chosen_positions[0]) + 1)) {
                    // Check if actually consecutive from k+1
                }
                if (box_val < N && state.is_on_top(box_val) && box_val == k + 1) {
                    state.carry_out(box_val);
                    k = box_val;
                    // Continue cascade
                    while (k + 1 < N && state.is_on_top(k + 1)) {
                        state.carry_out(k + 1);
                        k++;
                    }
                    break;
                }
            }
        }
    }

    out_ops = std::move(state.ops);
    return state.energy;
}

// Simple greedy (no splitting) for comparison / as baseline
long long run_greedy(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                     std::vector<std::pair<int,int>>& out_ops) {
    State state(N, M, init_stacks, true);

    for (int k = 0; k < N; k++) {
        if (state.is_on_top(k)) {
            state.carry_out(k);
            continue;
        }

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos;

        if (block_size == 0) {
            state.carry_out(k);
            continue;
        }

        int first_box = state.stacks[src][pos + 1];
        int dest = best_waste_dest(state, k, src, block_size);
        state.move(first_box, dest);
        state.carry_out(k);
    }

    out_ops = std::move(state.ops);
    return state.energy;
}

// Parameterized cascade for SA tuning
struct CascadeParams {
    int max_splits;
    int window;
    double waste_cover_weight;
    double waste_height_weight;
    double waste_empty_penalty;
    double critical_cover_weight;
    double critical_height_weight;
    double benefit_threshold;
};

long long run_cascade_param(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                            std::vector<std::pair<int,int>>& out_ops, const CascadeParams& params) {
    State state(N, M, init_stacks, true);

    auto eval_waste_dest = [&](int dest, int current_target, int src_stack) -> double {
        double score = 0.0;
        const auto& dstack = state.stacks[dest];
        for (int b : dstack) {
            if (b > current_target && b < current_target + 30) {
                score += params.waste_cover_weight / (b - current_target);
            }
        }
        score -= (double)dstack.size() * params.waste_height_weight;
        if (dstack.empty()) score += params.waste_empty_penalty;
        return score;
    };

    auto eval_crit_dest = [&](int dest, int current_target, int src_stack) -> double {
        double score = 0.0;
        const auto& dstack = state.stacks[dest];
        for (int b : dstack) {
            if (b > current_target && b < current_target + 30) {
                score += params.critical_cover_weight / (b - current_target);
            }
        }
        score += (double)dstack.size() * params.critical_height_weight;
        return score;
    };

    auto pick_waste_dest = [&](int current_target, int src_stack) -> int {
        double best = 1e18; int bd = -1;
        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double s = eval_waste_dest(d, current_target, src_stack);
            if (s < best) { best = s; bd = d; }
        }
        return bd;
    };

    auto pick_crit_dest = [&](int current_target, int src_stack) -> int {
        double best = 1e18; int bd = -1;
        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double s = eval_crit_dest(d, current_target, src_stack);
            if (s < best) { best = s; bd = d; }
        }
        return bd;
    };

    for (int k = 0; k < N; k++) {
        if (state.is_on_top(k)) {
            state.carry_out(k);
            continue;
        }

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos;

        if (block_size == 0) {
            state.carry_out(k);
            continue;
        }

        std::vector<int> block(state.stacks[src].begin() + pos + 1, state.stacks[src].end());

        // Find upcoming boxes in block
        std::vector<std::pair<int,int>> upcoming;
        for (int j = 1; j <= params.window && k + j < N; j++) {
            int target = k + j;
            if (state.box_stack[target] == src && state.box_pos[target] > pos) {
                int p_in_block = state.box_pos[target] - pos - 1;
                upcoming.push_back({p_in_block, target});
            }
        }
        std::sort(upcoming.begin(), upcoming.end());

        // Select split positions
        std::vector<int> chosen_positions;

        // Consecutive prefix from k+1
        int consecutive_end = k;
        for (auto& [p, v] : upcoming) {
            if (v == consecutive_end + 1) {
                chosen_positions.push_back(p);
                consecutive_end = v;
                if ((int)chosen_positions.size() >= params.max_splits) break;
            }
        }

        // Additional high-value splits
        if ((int)chosen_positions.size() < params.max_splits) {
            for (auto& [p, v] : upcoming) {
                if ((int)chosen_positions.size() >= params.max_splits) break;
                bool already = false;
                for (int cp : chosen_positions) if (cp == p) { already = true; break; }
                if (already) continue;

                int next_above = block_size;
                for (int cp : chosen_positions) if (cp > p && cp < next_above) next_above = cp;
                int would_be_above = next_above - p - 1;
                double benefit = (double)would_be_above / (v - k);
                if (benefit > params.benefit_threshold) {
                    chosen_positions.push_back(p);
                    std::sort(chosen_positions.begin(), chosen_positions.end());
                }
            }
        }

        if (chosen_positions.empty()) {
            int dest = pick_waste_dest(k, src);
            state.move(block[0], dest);
            state.carry_out(k);
        } else {
            std::sort(chosen_positions.begin(), chosen_positions.end());

            struct Chunk { int start, end; bool is_waste; };
            std::vector<Chunk> chunks;

            int top_start = chosen_positions.back() + 1;
            if (top_start < block_size) {
                chunks.push_back({top_start, block_size - 1, true});
            }

            for (int i = (int)chosen_positions.size() - 1; i >= 0; i--) {
                int chunk_end = chosen_positions[i];
                int chunk_start = (i > 0) ? chosen_positions[i-1] + 1 : 0;
                chunks.push_back({chunk_start, chunk_end, false});
            }

            for (auto& chunk : chunks) {
                int bottom_box = block[chunk.start];
                int dest;
                if (chunk.is_waste) {
                    dest = pick_waste_dest(k, src);
                } else {
                    dest = pick_crit_dest(k, src);
                }
                state.move(bottom_box, dest);
            }

            state.carry_out(k);

            // Cascade
            while (k + 1 < N && state.is_on_top(k + 1)) {
                state.carry_out(k + 1);
                k++;
            }
        }
    }

    out_ops = std::move(state.ops);
    return state.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--; // 0-index
        }
    }

    // Run multiple strategies and pick the best
    std::vector<std::pair<int,int>> best_ops;
    long long best_energy = 1e18;

    // Strategy 1: Conservative cascade (consecutive splits only)
    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_cascade(init_stacks, N, M, ops, 3, 20);
        if (e < best_energy) { best_energy = e; best_ops = std::move(ops); }
    }

    // Strategy 2: Aggressive cascade
    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_cascade_aggressive(init_stacks, N, M, ops, 4, 30);
        if (e < best_energy) { best_energy = e; best_ops = std::move(ops); }
    }

    // Strategy 3: Simple greedy (no splitting)
    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_greedy(init_stacks, N, M, ops);
        if (e < best_energy) { best_energy = e; best_ops = std::move(ops); }
    }

    // SA over parameters
    CascadeParams best_params = {3, 25, 50.0, 0.01, 2.0, 50.0, 0.05, 1.5};
    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_cascade_param(init_stacks, N, M, ops, best_params);
        if (e < best_energy) { best_energy = e; best_ops = std::move(ops); }
    }

    // SA to tune parameters
    CascadeParams current_params = best_params;
    long long current_energy = best_energy;
    double T_init = 30.0, T_final = 0.1;

    while (elapsed() < TIME_LIMIT) {
        CascadeParams new_params = current_params;

        // Randomly perturb one parameter
        int which = rng.randint(0, 7);
        switch (which) {
            case 0: new_params.max_splits = std::max(1, std::min(5, current_params.max_splits + rng.randint(-1, 1))); break;
            case 1: new_params.window = std::max(5, std::min(50, current_params.window + rng.randint(-5, 5))); break;
            case 2: new_params.waste_cover_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.4); break;
            case 3: new_params.waste_height_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.4); break;
            case 4: new_params.waste_empty_penalty *= (1.0 + (rng.randdbl() - 0.5) * 0.4); break;
