#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.90;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks;
    std::vector<int> box_stack;
    std::vector<int> box_pos;
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record;

    State() : N(0), M(0), energy(0), record(true) {}

    State(int n, int m, const std::vector<std::vector<int>>& init, bool rec = true)
        : N(n), M(m), energy(0), record(rec) {
        stacks = init;
        box_stack.resize(N);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_pos[stacks[i][j]] = j;
            }
        }
        if (record) ops.reserve(N * 3);
    }

    void move(int v, int dest) {
        int src = box_stack[v];
        int pos = box_pos[v];
        int dest_base = (int)stacks[dest].size();
        int num_moved = (int)stacks[src].size() - pos;

        for (int i = pos; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_pos[b] = dest_base + (i - pos);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(pos);
        energy += num_moved + 1;
        if (record) ops.push_back({v + 1, dest + 1});
    }

    void carry_out(int v) {
        int src = box_stack[v];
        stacks[src].pop_back();
        if (record) ops.push_back({v + 1, 0});
    }

    bool is_on_top(int v) const {
        int src = box_stack[v];
        return box_pos[v] == (int)stacks[src].size() - 1;
    }
};

struct CascadeParams {
    int max_splits;
    int window;
    double waste_cover_weight;
    double waste_height_weight;
    double waste_empty_penalty;
    double crit_cover_weight;
    double crit_height_weight;
    double benefit_threshold;
};

long long run_solution(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                       std::vector<std::pair<int,int>>& out_ops, const CascadeParams& params) {
    State state(N, M, init_stacks, true);

    auto eval_waste = [&](int dest, int k, int src) -> double {
        double score = 0.0;
        const auto& ds = state.stacks[dest];
        for (int b : ds) {
            if (b > k && b < k + 30) {
                score += params.waste_cover_weight / (b - k);
            }
        }
        score -= (double)ds.size() * params.waste_height_weight;
        if (ds.empty()) score += params.waste_empty_penalty;
        return score;
    };

    auto eval_crit = [&](int dest, int k, int src) -> double {
        double score = 0.0;
        const auto& ds = state.stacks[dest];
        for (int b : ds) {
            if (b > k && b < k + 30) {
                score += params.crit_cover_weight / (b - k);
            }
        }
        score += (double)ds.size() * params.crit_height_weight;
        return score;
    };

    auto pick_waste = [&](int k, int src) -> int {
        double best = 1e18; int bd = -1;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double s = eval_waste(d, k, src);
            if (s < best) { best = s; bd = d; }
        }
        return bd;
    };

    auto pick_crit = [&](int k, int src) -> int {
        double best = 1e18; int bd = -1;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double s = eval_crit(d, k, src);
            if (s < best) { best = s; bd = d; }
        }
        return bd;
    };

    int k = 0;
    while (k < N) {
        // Try to carry out consecutive boxes already on top
        while (k < N && state.is_on_top(k)) {
            state.carry_out(k);
            k++;
        }
        if (k >= N) break;

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos;

        // Snapshot the block above k (these are 0-indexed box values)
        std::vector<int> block(state.stacks[src].begin() + pos + 1, state.stacks[src].end());

        // Find upcoming consecutive boxes in this block: k+1, k+2, ...
        // that are currently above k in the same stack
        std::vector<int> consec_in_block; // box values that form consecutive sequence from k+1
        {
            int next_expected = k + 1;
            // Check all upcoming boxes in this block within window
            std::vector<std::pair<int,int>> upcoming_sorted; // (pos_in_block, box_val)
            for (int j = 1; j <= params.window && k + j < N; j++) {
                int target = k + j;
                if (state.box_stack[target] == src && state.box_pos[target] > pos) {
                    int pib = state.box_pos[target] - pos - 1;
                    upcoming_sorted.push_back({pib, target});
                }
            }
            // The consecutive sequence must be k+1, k+2, ... all present in block
            for (int j = 1; j <= params.window && k + j < N; j++) {
                int target = k + j;
                bool found = false;
                for (auto& [p, v] : upcoming_sorted) {
                    if (v == target) { found = true; break; }
                }
                if (found) {
                    consec_in_block.push_back(target);
                } else {
                    break;
                }
            }
        }

        // Limit consecutive cascade to max_splits
        if ((int)consec_in_block.size() > params.max_splits) {
            consec_in_block.resize(params.max_splits);
        }

        if (consec_in_block.empty()) {
            // No cascade possible: move entire block, then carry out k
            int dest = pick_waste(k, src);
            int bottom_box = block[0];
            state.move(bottom_box, dest);
            state.carry_out(k);
            k++;
        } else {
            // Cascade splitting: split the block so each consecutive box ends up on top
            // Get positions in block for each cascade target
            std::vector<std::pair<int,int>> split_targets; // (pos_in_block, box_value)
            for (int t : consec_in_block) {
                int pib = state.box_pos[t] - pos - 1;
                split_targets.push_back({pib, t});
            }
            // Sort by position ascending (bottom to top of block)
            std::sort(split_targets.begin(), split_targets.end());

            // Define chunks by split positions
            // A chunk is everything from one split point to the next
            // The split target should end up on TOP of its chunk

            std::vector<int> split_positions;
            for (auto& [p, v] : split_targets) split_positions.push_back(p);

            // Chunks from top of block to bottom (we move top chunks first):
            struct Chunk { int start, end; bool is_waste; };
            std::vector<Chunk> chunks;

            // Top waste chunk: above highest split target
            if (split_positions.back() + 1 < block_size) {
                chunks.push_back({split_positions.back() + 1, block_size - 1, true});
            }

            // Critical chunks from top to bottom
            for (int i = (int)split_positions.size() - 1; i >= 0; i--) {
                int ce = split_positions[i];
                int cs = (i > 0) ? split_positions[i-1] + 1 : 0;
                chunks.push_back({cs, ce, false});
            }

