                int dest;
                if (chunk.is_waste) {
                    dest = pick_waste(k, src);
                } else {
                    dest = pick_crit(k, src);
                }
                state.move(bottom_box_val, dest);
            }

            // Now k is on top of src, carry it out
            state.carry_out(k);
            k++;

            // Carry out the consecutive boxes (each should be on top of its stack)
            for (int t : consec_in_block) {
                if (state.is_on_top(t)) {
                    state.carry_out(t);
                    k++;
                } else {
                    break;
                }
            }
        }
    }

    out_ops = std::move(state.ops);
    return state.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    CascadeParams best_params = {4, 25, 50.0, 0.01, 2.0, 50.0, 0.05, 1.5};

    std::vector<std::pair<int,int>> best_ops;
    long long best_energy;

    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_solution(init_stacks, N, M, ops, best_params);
        best_energy = e;
        best_ops = std::move(ops);
    }

    // SA over parameters
    CascadeParams current_params = best_params;
    long long current_energy = best_energy;
    double T_init = 20.0, T_final = 0.1;

    int iter = 0;
    while (elapsed() < TIME_LIMIT) {
        iter++;
        CascadeParams new_params = current_params;

        int which = rng.randint(0, 7);
        switch (which) {
            case 0: new_params.max_splits = std::max(1, std::min(6, current_params.max_splits + rng.randint(-1, 1))); break;
            case 1: new_params.window = std::max(5, std::min(50, current_params.window + rng.randint(-3, 3))); break;
            case 2: new_params.waste_cover_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
            case 3: new_params.waste_height_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
            case 4: new_params.waste_empty_penalty *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
            case 5: new_params.crit_cover_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
            case 6: new_params.crit_height_weight *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
            case 7: new_params.benefit_threshold *= (1.0 + (rng.randdbl() - 0.5) * 0.3); break;
        }

        std::vector<std::pair<int,int>> ops;
        long long e = run_solution(init_stacks, N, M, ops, new_params);

        double progress = elapsed() / TIME_LIMIT;
        double T = T_init * std::pow(T_final / T_init, progress);

        double delta = (double)(e - current_energy);
        if (delta < 0 || rng.randdbl() < std::exp(-delta / T)) {
            current_energy = e;
            current_params = new_params;
            if (e < best_energy) {
                best_energy = e;
                best_ops = std::move(ops);
                best_params = new_params;
            }
        }
    }

    // Validate ops count
    if ((int)best_ops.size() > 5000) {
        // Fallback: run with fewer splits
        CascadeParams safe_params = best_params;
        safe_params.max_splits = 1;
        std::vector<std::pair<int,int>> ops;
        run_solution(init_stacks, N, M, ops, safe_params);
        if ((int)ops.size() <= 5000) {
            best_ops = std::move(ops);
        }
    }

    for (auto& [v, i] : best_ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
