    State state(N, M, init_stacks, true);

    // Evaluate destination for moving a chunk of given size
    // block_contents: the boxes in this chunk (bottom to top)
    // Lower score = better
    auto eval_dest = [&](int dest, int k, int src, const std::vector<int>& block_contents, bool is_critical) -> double {
        double score = 0.0;
        const auto& ds = state.stacks[dest];

        // Penalty for covering soon-needed boxes already on dest
        for (int b : ds) {
            if (b > k && b < k + 30) {
                double w = is_critical ? params.crit_cover_weight : params.waste_cover_weight;
                score += w / (b - k);
            }
        }

        if (is_critical) {
            // For critical chunks (target on top), prefer shorter dest stacks
            score += (double)ds.size() * params.crit_height_weight;
        } else {
            // For waste, prefer taller stacks (concentrate waste)
            score -= (double)ds.size() * params.waste_height_weight;
            if (ds.empty()) score += params.waste_empty_penalty;
        }

        // Penalty for putting soon-needed boxes under other boxes in this chunk
        // The chunk is placed as-is, top box of chunk will be on top of dest
        for (int i = 0; i < (int)block_contents.size() - 1; i++) {
            int b = block_contents[i];
            if (b > k && b < k + 30) {
                int depth = (int)block_contents.size() - 1 - i;
                score += params.waste_cover_weight * depth / (b - k);
            }
        }

