# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>
#include <queue>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.92;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

// Compact state for efficient simulation
struct State {
    int N, M;
    std::vector<std::vector<int>> stacks;
    std::vector<int> box_stack;
    std::vector<int> box_pos;
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record;

    State() : N(0), M(0), energy(0), record(false) {}

    State(int n, int m, const std::vector<std::vector<int>>& init, bool rec = false)
        : N(n), M(m), energy(0), record(rec) {
        stacks = init;
        box_stack.resize(N);
        box_pos.resize(N);
        for (int i = 0; i < M; i++)
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_pos[stacks[i][j]] = j;
            }
        if (rec) ops.reserve(N * 3);
    }

    void move(int v, int dest) {
        int src = box_stack[v];
        int pos_v = box_pos[v];
        int num = (int)stacks[src].size() - pos_v;
        int db = (int)stacks[dest].size();
        for (int i = pos_v; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_pos[b] = db + (i - pos_v);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(pos_v);
        energy += num + 1;
        if (record) ops.push_back({v + 1, dest + 1});
    }

    void carry_out(int v) {
        int src = box_stack[v];
        stacks[src].pop_back();
        if (record) ops.push_back({v + 1, 0});
    }

    bool is_on_top(int v) const {
        return box_pos[v] == (int)stacks[box_stack[v]].size() - 1;
    }

    int depth(int v) const {
        return (int)stacks[box_stack[v]].size() - 1 - box_pos[v];
    }
};

// Evaluate how costly it is to place a block onto destination d
// considering how it will interfere with future box removals.
// This is the core heuristic.
double evaluate_move(const State& st, int k, int src, int dest,
                     int block_start_pos, // position in src of bottom of block being moved
                     int block_size) {
    double score = 0.0;
    const auto& ds = st.stacks[dest];
    int N = st.N;

    // Penalty for burying soon-needed boxes on destination
    for (int i = 0; i < (int)ds.size(); i++) {
        int b = ds[i];
        if (b > k && b < k + 40) {
            // This box will be buried deeper
            double urgency = 1.0 / (b - k);
            int current_depth = (int)ds.size() - 1 - i;
            int new_depth = current_depth + block_size;
            score += 3.0 * urgency * (new_depth - current_depth);
        }
    }

    // Penalty based on how soon-needed the bottom boxes of our block are
    // (they'll be buried under the rest of the block)
    for (int i = block_start_pos; i < block_start_pos + block_size; i++) {
        int b = st.stacks[src][i];
        if (b > k && b < k + 40) {
            double urgency = 1.0 / (b - k);
            int depth_in_block = (block_start_pos + block_size - 1) - i; // 0 = top
            score += 2.0 * urgency * depth_in_block;
        }
    }

    // Slight preference for stacks that already have high (far-future) boxes
    // (waste consolidation)
    if (!ds.empty()) {
        int min_label = N;
        for (int b : ds) min_label = std::min(min_label, b);
        if (min_label > k + 30) {
            score -= 0.5; // Good: this stack has only far-future boxes
        }
    }

    // Penalty for using empty stacks (they're valuable as buffers)
    if (ds.empty()) score += 3.0;

    // Small penalty for total height (tall stacks are harder to work with)
    score += (double)(ds.size() + block_size) * 0.02;

    return score;
}

// Run a single greedy simulation with lookahead for splitting decisions
long long run_greedy_split(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int,int>>& out_ops,
                           int split_lookahead = 6, bool do_preemptive = false) {
    State state(N, M, init_stacks, true);

    int k = 0;
    while (k < N) {
        while (k < N && state.is_on_top(k)) {
            state.carry_out(k);
            k++;
        }
        if (k >= N) break;

        int src = state.box_stack[k];
        int pos = state.box_pos[k];
        int block_size = (int)state.stacks[src].size() - 1 - pos;

        // Check if k+1, k+2, ... are also in this block above k
        // If so, we can potentially split to create cascading carry-outs
        std::vector<int> consec;
        for (int j = 1; j <= split_lookahead && k + j < N; j++) {
            int t = k + j;
            if (state.box_stack[t] == src && state.box_pos[t] > pos) {
                consec.push_back(t);
            } else {
                break;
            }
        }

        // Decide: is splitting worthwhile?
        // Splitting into (consec.size() + 1) chunks costs consec.size() extra moves
        // Each extra move costs (chunk_size + 1) energy
        // Benefit: each cascade box saves us a future move of everything above it
        // Estimate future cost to expose box t if NOT split:
        // It will be at some depth in wherever we put the block. Cost ~ depth + 1

        // Simple heuristic: split for consecutive boxes that are "deep" in the block
        // Only split if the boxes between them are ≤ 2 (cheap split)

        // More aggressive: always split for consecutive sequences
        // The cost per extra chunk is (chunk_size + 1)
        // The savings per cascade is (future_block_above + 1) which is at least 1

        // Let's compute cost vs benefit:
        // If we DON'T split: one move costs (block_size + 1)
        //   Then each consec[i] will need to be exposed later, costing at least 2 each
        // If we DO split into n+1 chunks (n = consec.size()):
        //   Moves cost sum(chunk_size_i + 1) = block_size + n + 1
        //   But we get n free carry-outs
        //   vs not-split: block_size + 1 + future_costs >= block_size + 1 + 2*n
        // So splitting is worth it when: block_size + n + 1 < block_size + 1 + 2*n
        //   i.e., n > 0 always! (n + 1 < 1 + 2n => true for n >= 1)
        // So we should ALWAYS split for consecutive boxes!

        // But wait: the split only gives free carry-outs if the cascade boxes end up
        // on top of their destination stacks. With our splitting, each cascade box
        // IS on top of its chunk, so it IS on top of the destination.
        // After carry-out of k, we go to k+1 which is on top of its dest. Perfect.

        // However, if the ops count would exceed 5000, we need to limit splits.

        if (!consec.empty()) {
            // Get positions of cascade targets in the block
            std::vector<std::pair<int,int>> tgt_pos; // (pos_in_block, box_val)
            for (int t : consec) {
                tgt_pos.push_back({state.box_pos[t] - pos - 1, t});
            }
            std::sort(tgt_pos.begin(), tgt_pos.end());

            std::vector<int> split_pos;
            for (auto& [p, v] : tgt_pos) split_pos.push_back(p);

            // Build chunks from top to bottom
            struct Chunk { int start, end; bool is_crit; };
            std::vector<Chunk> chunks;

            if (split_pos.back() + 1 < block_size) {
                chunks.push_back({split_pos.back() + 1, block_size - 1, false});
            }
            for (int i = (int)split_pos.size() - 1; i >= 0; i--) {
                int ce = split_pos[i];
                int cs = (i > 0) ? split_pos[i-1] + 1 : 0;
                chunks.push_back({cs, ce, true});
