// Greedy with parameterized weights for SA tuning
struct Weights {
    double cover_weight;     // penalty for covering soon-needed boxes
    double cover_decay;      // how quickly urgency falls off with distance
    double block_urgency;    // penalty for burying block boxes that are soon needed
    double empty_penalty;    // cost of using empty stack
    double height_factor;    // cost per height unit
    double consolidate;      // bonus for putting waste with other waste
    int split_limit;         // max consecutive splits
};

long long run_weighted(const std::vector<std::vector<int>>& init_stacks, int N, int M,
