            if (b > k && b < k + 40) {
                score += w.cover_weight / std::pow(b - k, w.cover_decay);
            }
        }

        for (int i = block_start; i < block_start + block_sz; i++) {
            int b = state.stacks[src][i];
            if (b > k && b < k + 40) {
                int depth_in_block = (block_start + block_sz - 1) - i;
                score += w.block_urgency * depth_in_block / std::pow(b - k, w.cover_decay);
            }
        }

        if (ds.empty()) score += w.empty_penalty;
        score += (double)(ds.size() + block_sz) * w.height_factor;

        if (!ds.empty()) {
            bool all_far = true;
            for (int b : ds) if (b <= k + 30) { all_far = false; break; }
            if (all_far) score -= w.consolidate;
        }

