}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    // Initial run with default weights
    Weights best_w = {3.0, 1.0, 2.0, 3.0, 0.02, 0.5, 5};
    std::vector<std::pair<int,int>> best_ops;
    long long best_energy;

    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_weighted(init_stacks, N, M, ops, best_w);
        best_energy = e;
        best_ops = std::move(ops);
    }

    // Also try the simpler greedy with splitting
    {
        std::vector<std::pair<int,int>> ops;
        long long e = run_greedy_split(init_stacks, N, M, ops, 5, false);
        if (e < best_energy) { best_energy = e; best_ops = std::move(ops); }
    }

    // SA over weights
    Weights cur_w = best_w;
    long long cur_energy = best_energy;
    double T_init = 15.0, T_final = 0.05;

    while (elapsed() < TIME_LIMIT) {
        Weights nw = cur_w;
        int which = rng.randint(0, 6);
        double factor = 1.0 + (rng.randdbl() - 0.5) * 0.4;
        switch (which) {
            case 0: nw.cover_weight = std::max(0.1, nw.cover_weight * factor); break;
            case 1: nw.cover_decay = std::max(0.3, std::min(2.5, nw.cover_decay * factor)); break;
            case 2: nw.block_urgency = std::max(0.1, nw.block_urgency * factor); break;
            case 3: nw.empty_penalty = std::max(0.0, nw.empty_penalty * factor); break;
            case 4: nw.height_factor = std::max(0.001, nw.height_factor * factor); break;
            case 5: nw.consolidate = std::max(0.0, nw.consolidate * factor); break;
            case 6: nw.split_limit = std::max(1, std::min(8, nw.split_limit + rng.randint(-1, 1))); break;
        }

        std::vector<std::pair<int,int>> ops;
        long long e = run_weighted(init_stacks, N, M, ops, nw);

        double progress = elapsed() / TIME_LIMIT;
        double T = T_init * std::pow(T_final / T_init, progress);
        double delta = (double)(e - cur_energy);

        if (delta < 0 || rng.randdbl() < std::exp(-delta / T)) {
            cur_energy = e;
            cur_w = nw;
            if (e < best_energy) {
                best_energy = e;
                best_ops = std::move(ops);
                best_w = nw;
            }
        }
    }

    if ((int)best_ops.size() > 5000) {
        // Emergency: run with split_limit=0
        Weights ew = best_w;
        ew.split_limit = 0;
        std::vector<std::pair<int,int>> ops;
        run_weighted(init_stacks, N, M, ops, ew);
        if ((int)ops.size() <= 5000) best_ops = std::move(ops);
    }

    for (auto& [v, i] : best_ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
