#include <algorithm>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.92;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) { return std::uniform_int_distribution<int>(lo, hi)(rng); }
    double randdbl() { return std::uniform_real_distribution<double>(0.0, 1.0)(rng); }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks;
    std::vector<int> box_stack, box_pos;
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record;

    State() : N(0), M(0), energy(0), record(false) {}
    State(int n, int m, const std::vector<std::vector<int>>& init, bool rec)
        : N(n), M(m), energy(0), record(rec) {
        stacks = init;
        box_stack.resize(N); box_pos.resize(N);
