            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_pos[stacks[i][j]] = j;
            }
        if (rec) ops.reserve(N * 2);
    }

    void move(int v, int dest) {
        int src = box_stack[v];
        int pv = box_pos[v];
        int num = (int)stacks[src].size() - pv;
        int db = (int)stacks[dest].size();
        for (int i = pv; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_pos[b] = db + (i - pv);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(pv);
        energy += num + 1;
        if (record) ops.push_back({v + 1, dest + 1});
    }

    void carry_out(int v) {
        stacks[box_stack[v]].pop_back();
        if (record) ops.push_back({v + 1, 0});
    }

    bool is_on_top(int v) const {
        return box_pos[v] == (int)stacks[box_stack[v]].size() - 1;
    }
};

// Simulate with a destination plan. plan[i] = dest for the i-th "expose" operation.
// Returns energy. If rec=true, populates ops.
long long simulate(const std::vector<std::vector<int>>& init, int N, int M,
                   const std::vector<int>& plan, std::vector<std::pair<int,int>>* ops_out) {
    bool rec = (ops_out != nullptr);
    State st(N, M, init, rec);
    int pi = 0;
    int k = 0;
    while (k < N) {
        while (k < N && st.is_on_top(k)) { st.carry_out(k); k++; }
        if (k >= N) break;
        int src = st.box_stack[k];
        int pos = st.box_pos[k];
        int bb = st.stacks[src][pos + 1];
        int dest = plan[pi] % M;
        if (dest == src) dest = (src + 1) % M;
        pi++;
        st.move(bb, dest);
        st.carry_out(k); k++;
