        st.energy += num + 1;
        st.stacks[st.box_stack[k]].pop_back();
        k++;
    }
    return st.energy;
}

// Generate a greedy plan
std::vector<int> greedy_plan(const std::vector<std::vector<int>>& init, int N, int M) {
    State st(N, M, init, false);
    std::vector<int> plan;
    plan.reserve(N);

    int k = 0;
    while (k < N) {
        while (k < N && st.is_on_top(k)) {
            st.stacks[st.box_stack[k]].pop_back();
            k++;
        }
        if (k >= N) break;

        int src = st.box_stack[k];
        int pos = st.box_pos[k];
        int block_size = (int)st.stacks[src].size() - 1 - pos;

        // Pick best destination
        double best_score = 1e18;
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;
            const auto& ds = st.stacks[d];

            // Penalty for covering soon-needed boxes on dest
            for (int b : ds) {
                if (b > k && b < k + 30) {
                    score += 5.0 / (b - k);
                }
            }

            // Penalty for putting soon-needed boxes from block deep
            for (int i = pos + 1; i < (int)st.stacks[src].size(); i++) {
                int b = st.stacks[src][i];
                if (b > k && b < k + 30) {
                    int depth = (int)st.stacks[src].size() - 1 - i;
                    score += 2.0 * depth / (b - k);
                }
            }

            if (ds.empty()) score += 2.5;
            score += (double)ds.size() * 0.02;

            if (score < best_score) { best_score = score; best_dest = d; }
        }

        plan.push_back(best_dest);

        // Apply move
        int bb = st.stacks[src][pos + 1];
        int pv = st.box_pos[bb];
        int num = (int)st.stacks[src].size() - pv;
        int db = (int)st.stacks[best_dest].size();
        for (int i = pv; i < (int)st.stacks[src].size(); i++) {
            int b = st.stacks[src][i];
            st.box_stack[b] = best_dest;
            st.box_pos[b] = db + (i - pv);
            st.stacks[best_dest].push_back(b);
        }
        st.stacks[src].resize(pv);
        st.energy += num + 1;
        st.stacks[st.box_stack[k]].pop_back();
        k++;
    }
    return plan;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    // Generate initial greedy plan
    std::vector<int> plan = greedy_plan(init_stacks, N, M);
    int plan_size = (int)plan.size();

    long long best_energy = simulate(init_stacks, N, M, plan, nullptr);
    std::vector<int> best_plan = plan;

    // SA optimization
    std::vector<int> cur_plan = plan;
    long long cur_energy = best_energy;

    double T_init = 50.0, T_final = 0.01;
    int max_block = std::max(1, plan_size / 10);

    while (elapsed() < TIME_LIMIT) {
        std::vector<int> new_plan = cur_plan;

        // Perturbation: randomly change 1-few entries
        double r = rng.randdbl();
        if (r < 0.4) {
            // Single point mutation
            int idx = rng.randint(0, plan_size - 1);
            new_plan[idx] = rng.randint(0, M - 1);
        } else if (r < 0.75) {
            // Block mutation (consecutive changes)
            int start = rng.randint(0, plan_size - 1);
            int len = rng.randint(1, std::min(max_block, plan_size - start));
            for (int i = start; i < start + len; i++) {
                new_plan[i] = rng.randint(0, M - 1);
            }
        } else if (r < 0.90) {
            // Swap two entries
            int i1 = rng.randint(0, plan_size - 1);
            int i2 = rng.randint(0, plan_size - 1);
            std::swap(new_plan[i1], new_plan[i2]);
        } else {
            // Targeted: increment/decrement one entry
            int idx = rng.randint(0, plan_size - 1);
            new_plan[idx] = (new_plan[idx] + rng.randint(1, M - 1)) % M;
        }

        long long new_energy = simulate(init_stacks, N, M, new_plan, nullptr);

        double progress = elapsed() / TIME_LIMIT;
        double T = T_init * std::pow(T_final / T_init, progress);
        double delta = (double)(new_energy - cur_energy);

        if (delta < 0 || rng.randdbl() < std::exp(-delta / T)) {
            cur_energy = new_energy;
            cur_plan = new_plan;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_plan = new_plan;
            }
        }
    }

    // Final output with best plan
    std::vector<std::pair<int,int>> ops;
    simulate(init_stacks, N, M, best_plan, &ops);

    for (auto& [v, i] : ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
